phase1.code:
fun main() {
    // ---- val (read-only) ----
    val name = "Kotlin-chan"
    println("Name: $name")
    // name = "Java-chan"  // ❌ Can't reassign

    // ---- var (mutable) ----
    var age = 25
    println("Age: $age")
    age = 26  // ✅ Can reassign
    println("New age: $age")

    // ---- Type inference ----
    val inferredString = "Hello"       // String
    val inferredInt = 42               // Int
    val inferredDouble = 3.14          // Double
    val inferredBoolean = true         // Boolean

    // ---- Explicit types ----
    val explicitString: String = "Hello"
    var explicitInt: Int = 42

    // ---- Runtime values ----
    val random = Math.random()         // Computed at runtime
    val result = calculateSomething()  // Can be from a function

    // ---- Val with late initialization ----
    // val can only be assigned once
    val pi = 3.14159
    // pi = 3.14  // ❌ Not allowed

    // ---- Best practices ----
    // 1. Use val by default
    // 2. Only use var when mutation is needed
    // 3. Prefer immutability for thread safety

    println("\n=== Summary ===")
    println("val = read-only (immutable)")
    println("var = mutable")
    println("Always prefer val over var")
}

fun calculateSomething(): Int {
    return 42
}

